    71  func ParseTracingConfig(cfg *setting.Cfg) (*TracingConfig, error) {
    72          if cfg == nil {
    73                  return nil, fmt.Errorf("cfg cannot be nil")
    74          }
    75          tc := NewEmptyTracingConfig()
    76          tc.ServiceName = "grafana"
    77          tc.ServiceVersion = cfg.BuildVersion
    78
    79          legacyAddress, legacyTags := "", ""
    80          if section, err := cfg.Raw.GetSection("tracing.jaeger"); err == nil {
    81                  legacyAddress = section.Key("address").MustString("")
    82                  if legacyAddress == "" {
    83                          host, port := os.Getenv(envJaegerAgentHost), os.Getenv(envJaegerAgentPort)
    84                          if host != "" || port != "" {
    85                                  legacyAddress = fmt.Sprintf("%s:%s", host, port)
    86                          }
    87                  }
    88                  legacyTags = section.Key("always_included_tag").MustString("")
    89                  tc.Sampler = section.Key("sampler_type").MustString("")
    90                  tc.SamplerParam = section.Key("sampler_param").MustFloat64(1)
    91                  tc.SamplerRemoteURL = section.Key("sampling_server_url").MustString("")
    92          }
    93          section := cfg.Raw.Section("tracing.opentelemetry")
    94          var err error
    95          // we default to legacy tag set (attributes) if the new config format is absent
    96          tc.CustomAttribs, err = splitCustomAttribs(section.Key("custom_attributes").MustString(legacyTags))
    97          if err != nil {
    98                  return nil, err
    99          }
   100
   101          // Allow overriding service name via configuration
   102          serviceName := section.Key("service_name").MustString("")
   103          if serviceName != "" {
   104                  tc.ServiceName = serviceName
   105          }
   106
   107          // if sampler_type is set in tracing.opentelemetry, we ignore the config in tracing.jaeger
   108          sampler := section.Key("sampler_type").MustString("")
   109          if sampler != "" {
   110                  tc.Sampler = sampler
   111          }
   112
   113          samplerParam := section.Key("sampler_param").MustFloat64(0)
   114          if samplerParam != 0 {
   115                  tc.SamplerParam = samplerParam
   116          }
   117
   118          samplerRemoteURL := section.Key("sampling_server_url").MustString("")
   119          if samplerRemoteURL != "" {
   120                  tc.SamplerRemoteURL = samplerRemoteURL
   121          }
   122
   123          section = cfg.Raw.Section("tracing.opentelemetry.jaeger")
   124          tc.enabled = noopExporter
   125
   126          // we default to legacy Jaeger agent address if the new config value is empty
   127          tc.Address = section.Key("address").MustString(legacyAddress)
   128          tc.Propagation = section.Key("propagation").MustString("")
   129          if tc.Address != "" {
   130                  tc.enabled = jaegerExporter
   131                  return tc, nil
   132          }
   133
   134          section = cfg.Raw.Section("tracing.opentelemetry.otlp")
   135          tc.Address = section.Key("address").MustString("")
   136          if tc.Address != "" {
   137                  tc.enabled = otlpExporter
   138          }
   139          tc.Propagation = section.Key("propagation").MustString("")
   140          tc.Insecure = section.Key("insecure").MustBool(true)
