   148  func splitCustomAttribs(s string) ([]attribute.KeyValue, error) {
   149          res := []attribute.KeyValue{}
   150
   151          attribs := strings.Split(s, ",")
   152          for _, v := range attribs {
   153                  parts := strings.SplitN(v, ":", 2)
   154                  if len(parts) > 1 {
   155                          res = append(res, attribute.String(parts[0], parts[1]))
   156                  } else if v != "" {
   157                          return nil, fmt.Errorf("custom attribute malformed - must be in 'key:value' form: %q", v)
   158                  }
   159          }
   160
   161          return res, nil
   162  }

