    13  // WithTracingHTTPLoggingAttributes adds tracing attributes to HTTP request logs.
    14  func WithTracingHTTPLoggingAttributes(handler http.Handler) http.Handler {
    15          return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
    16                  spanCtx := trace.SpanContextFromContext(r.Context())
    17                  if !spanCtx.IsValid() {
    18                          spanCtx = spanContextFromHeaders(r)
    19                  }
    20
    21                  if spanCtx.HasTraceID() {
    22                          httplog.AddKeyValue(r.Context(), "traceID", spanCtx.TraceID().String())
    23                  }
    24
    25                  if spanCtx.HasSpanID() {
    26                          httplog.AddKeyValue(r.Context(), "spanID", spanCtx.SpanID().String())
    27                  }
    28
    29                  handler.ServeHTTP(w, r)
    30          })
    31  }
    32
    33  // spanContextFromHeaders extracts a span context directly from request headers
    34  // using OTel propagators. This is a fallback for when the current span in the
    35  // request context has no valid trace context (e.g. noop TracerProvider overwrote
    36  // a previously-extracted remote span context).
    37  func spanContextFromHeaders(r *http.Request) trace.SpanContext {
    38          carrier := propagation.HeaderCarrier(r.Header)
    39
    40          ctx := otel.GetTextMapPropagator().Extract(context.Background(), carrier)
    41          if sc := trace.SpanContextFromContext(ctx); sc.IsValid() {
    42                  return sc
    43          }
    44
    45          // The kube-aggregator drops standard traceparent but preserves a custom
    46          // header injected by the ST proxy. Try that as a last resort.
    47          if tp := r.Header.Get("Grafana-Upstream-Traceparent"); tp != "" {
    48                  prop := propagation.TraceContext{}
    49                  upstreamCarrier := propagation.MapCarrier{"traceparent": tp}
    50                  ctx = prop.Extract(context.Background(), upstreamCarrier)
    51                  return trace.SpanContextFromContext(ctx)
    52          }
    53
    54          return trace.SpanContext{}
    55  }

