    17  // Listener implements dskit's services.Listener interface to add comprehensive tracing
    18  // for service state transitions. It creates individual spans for each service state
    19  // (Starting, Running, Stopping) to track their durations, providing detailed timing
    20  // information about service lifecycle performance.
    21  type Listener struct {
    22          serviceName string
    23
    24          ctx        context.Context
    25          parentSpan trace.Span
    26          stateSpan  trace.Span
    27  }
    28
    29  // NewListener creates a new tracing listener for the given service.
    30  func NewListener(ctx context.Context, serviceName string) *Listener {
    31          l := &Listener{
    32                  ctx:         ctx,
    33                  serviceName: serviceName,
    34          }
    35          return l
    36  }
    37
    38  // Starting is called when the service transitions from NEW to STARTING.
    39  func (l *Listener) Starting() {
    40          // Create the parent span when the service starts
    41          spanCtx, span := tracing.Start(l.ctx, l.serviceName)
    42          l.ctx = spanCtx
    43          l.parentSpan = span
    44
    45          l.startSpan(services.Starting, nil)
    46  }
    47
    48  // Running is called when the service transitions from STARTING to RUNNING.
    49  func (l *Listener) Running() {
    50          l.endSpan(nil)
    51          l.startSpan(services.Running, nil)
    52  }
    53
    54  // Stopping is called when the service transitions to the STOPPING state.
    55  func (l *Listener) Stopping(from services.State) {
    56          l.endSpan(nil)
    57          l.startSpan(services.Stopping, &from)
    58  }
    59
    60  // Terminated is called when the service transitions to the TERMINATED state.
    61  func (l *Listener) Terminated(from services.State) {
    62          l.endSpan(nil)
    63          l.endParentSpan(from, nil)
    64  }
    65
    66  // Failed is called when the service transitions to the FAILED state.
    67  func (l *Listener) Failed(from services.State, failure error) {
    68          l.endSpan(failure)
    69          l.endParentSpan(from, failure)
    70  }
    71
    72  // startSpan creates and stores a span for the given state
    73  func (l *Listener) startSpan(toState services.State, fromState *services.State) {
    74          spanName := fmt.Sprintf("%s Service", toState.String())
    75          _, span := tracing.Start(l.ctx, spanName, semconv.GrafanaServiceName(l.serviceName))
    76          attributes := []attribute.KeyValue{
    77                  semconv.GrafanaServiceName(l.serviceName),
    78          }
    79          if fromState != nil {
    80                  attributes = append(attributes, attribute.String("modules.tracing.from_state", fromState.String()))
    81          }
    82          span.SetAttributes(attributes...)
    83          l.stateSpan = span
    84  }
