   102  // endParentSpan safely ends and removes the parent span
   103  // If err is provided, it will be recorded on the parent span before ending
   104  func (l *Listener) endParentSpan(from services.State, err error) {
   105          if l.parentSpan == nil || !l.parentSpan.IsRecording() {
   106                  return
   107          }
   108          l.parentSpan.SetAttributes(attribute.String("modules.tracing.final_state", from.String()))
